module voltage_sensor (
    input [4:0] voltage_input,
    output reg is_high
);
  wire [4:0] _tap_voltage_input = voltage_input & {5{1'b1}};

    parameter REF_VOLTAGE = 10;

    always @* begin
        if (voltage_input > REF_VOLTAGE) 
            is_high = 1;
        else 
            is_high = 0;
    end
endmodule
